import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty grid when given empty grid");
  it.todo("should kill a single cell with no neighbors (underpopulation)");
  it.todo("should kill two adjacent cells that each have only one neighbor (underpopulation)");
  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
  it.todo("should keep a live cell alive when it has exactly 2 live neighbors (survival)");
  it.todo("should keep a live cell alive when it has exactly 3 live neighbors (survival)");
  it.todo("should kill a live cell when it has 4 or more live neighbors (overpopulation)");
  it.todo("should keep a block pattern stable across generations (still life)");
  it.todo("should oscillate a blinker pattern to its alternate form");
});
